// ============================================================
// ISOLATED WORKFLOW — Telegram Signal → Grok Analyzer
// Extract & format the signal text from Telegram channel post
// Build the Grok analysis prompt with real portfolio context
// ============================================================

const item = $input.first().json;

// Channel posts arrive as 'channel_post' (not 'message')
const post = item.channel_post || item.message || {};
const text = post.text || post.caption || '[No text content]';

// Extract metadata for logging
const chatTitle = post.chat?.title || 'Signals Channel';
const chatType = post.chat?.type || 'channel';
const messageDate = post.date
  ? new Date(post.date * 1000).toISOString()
  : new Date().toISOString();
const messageId = post.message_id || 'N/A';

// ============================================================
// ACTIVE TICKERS — Santosh's current watchlist
// Update this list as your portfolio changes
// ============================================================
const activeTickers = [
  'TSLA', 'NVDA', 'AMD', 'GILD', 'MSFT', 'CRWV', 'NBIS', 'SPY',
  'CRM', 'META', 'GS', 'PYPL', 'DIS', 'GM', 'ARM', 'MU', 'ASML',
  'QQQ', 'DIA', 'NTAP', 'NVTS', 'LITE', 'CVNA'
];

// Try to extract ticker from signal
const tickerMatch = text.match(/\$([A-Z]{1,5})/)
  || text.match(/\b(TSLA|NVDA|AMD|GILD|MSFT|CRWV|NBIS|SPY|CRM|META|GS|PYPL|DIS|GM|ARM|MU|ASML|QQQ|DIA|NTAP|NVTS|LITE|CVNA)\b/);
const ticker = tickerMatch ? tickerMatch[1] : 'UNKNOWN';
const isActiveTicker = activeTickers.includes(ticker);

// ============================================================
// PORTFOLIO CONTEXT — Real current state
// Update these numbers periodically for accurate analysis
// ============================================================
const portfolioContext = {
  positions: 38,
  exposure: '$190K',
  exposureLimit: '$200K',
  marginUsage: '95%',
  marginCap: '50%',
  bias: 'heavy AI/tech (NVDA, AMD, MSFT, META, ARM, MU, ASML)',
  riskStatus: 'OVER LIMIT — no new positions until stops/targets close',
  activeStrategy: 'Regime-first, Bayesian-weighted, 8-layer filter pipeline',
  aiEngine: 'Grok-3 (primary), Perplexity (backup)',
  killSwitchThresholds: 'Daily loss >2%, Margin >40%, Positions >25, Exposure >$200K'
};

// Build the analysis prompt
const analysisPrompt = `Here is a new trading signal from my Broad Scanner v3.0: ${text}.

Current portfolio context:
- ${portfolioContext.positions} open positions with ~${portfolioContext.exposure} total exposure (limit: ${portfolioContext.exposureLimit})
- Margin usage: ${portfolioContext.marginUsage} (cap: ${portfolioContext.marginCap})
- Heavy AI/tech bias: ${portfolioContext.bias}
- Risk status: ${portfolioContext.riskStatus}
- Kill switch thresholds: ${portfolioContext.killSwitchThresholds}
- Signal ticker: ${ticker} (${isActiveTicker ? 'ACTIVE in portfolio' : 'NOT in current portfolio'})

Analyze the signal for:
1. Fit with existing holdings and sector exposure
2. Correlation risk with the 38 open AI/tech-heavy positions
3. Potential overlap or redundancy with existing positions
4. Risk level given current margin/exposure being over limits
5. Whether this adds or reduces portfolio concentration
6. Short actionable recommendation: TAKE IT / SKIP / WATCH

Be direct. Keep response under 200 words.`;

return [{
  json: {
    signalText: text,
    analysisPrompt: analysisPrompt,
    ticker: ticker,
    isActiveTicker: isActiveTicker,
    chatTitle: chatTitle,
    chatType: chatType,
    messageDate: messageDate,
    messageId: messageId,
    portfolioPositions: portfolioContext.positions,
    portfolioExposure: portfolioContext.exposure
  }
}];

// ============================================================
// ISOLATED WORKFLOW — Log the Grok analysis result
// Structures output for execution history review
// Optional: connect to Google Sheets for persistent logging
// ============================================================

const input = $input.first().json;
const signalData = $('Format Signal Prompt').first().json;

const logEntry = {
  timestamp: new Date().toISOString(),
  ticker: signalData.ticker,
  isActiveTicker: signalData.isActiveTicker,
  messageId: signalData.messageId,
  chatTitle: signalData.chatTitle,
  originalSignal: signalData.signalText,
  grokAnalysis: input.output || input.text || JSON.stringify(input),
  portfolioPositions: signalData.portfolioPositions,
  portfolioExposure: signalData.portfolioExposure,
  messageDate: signalData.messageDate,
  status: 'analyzed'
};

// Extract recommendation from Grok's response
const analysis = logEntry.grokAnalysis.toUpperCase();
if (analysis.includes('TAKE IT')) {
  logEntry.recommendation = 'TAKE IT';
} else if (analysis.includes('SKIP')) {
  logEntry.recommendation = 'SKIP';
} else if (analysis.includes('WATCH')) {
  logEntry.recommendation = 'WATCH';
} else {
  logEntry.recommendation = 'UNKNOWN';
}

console.log(`[Grok Signal Analyzer] ${signalData.ticker} | ${logEntry.recommendation} | ${signalData.signalText?.substring(0, 80)}`);
console.log(`[Grok Signal Analyzer] Analysis: ${logEntry.grokAnalysis?.substring(0, 150)}`);

return [{ json: logEntry }];
